import React, { useCallback, useState } from 'react';
import { useDropzone } from 'react-dropzone';

const s = {
  zone: (active) => ({
    border: `2px dashed ${active ? '#2563eb' : '#d1d5db'}`,
    borderRadius: 10,
    padding: '32px 20px',
    textAlign: 'center',
    cursor: 'pointer',
    background: active ? '#eff6ff' : '#f9fafb',
    transition: 'all 0.2s',
  }),
  icon: { fontSize: 36, marginBottom: 10 },
  title: { fontWeight: 600, fontSize: 14, color: '#1f2937', marginBottom: 4 },
  sub: { fontSize: 12, color: '#6b7280' },
  fileList: { marginTop: 16 },
  fileItem: {
    display: 'flex',
    alignItems: 'center',
    gap: 10,
    padding: '8px 12px',
    background: '#fff',
    border: '1px solid #e5e7eb',
    borderRadius: 6,
    marginBottom: 6,
    fontSize: 13,
  },
  removeBtn: {
    marginLeft: 'auto',
    background: 'none',
    border: 'none',
    color: '#9ca3af',
    cursor: 'pointer',
    fontSize: 16,
    lineHeight: 1,
    padding: '0 4px',
  },
};

export default function UploadZone({ files, setFiles }) {
  const onDrop = useCallback((accepted) => {
    // Replace all previous files with newly selected ones (don't accumulate)
    setFiles(accepted);
  }, [setFiles]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: { 'application/pdf': ['.pdf'], 'application/vnd.openxmlformats-officedocument.wordprocessingml.document': ['.docx'] },
  });

  const remove = (name) => setFiles(prev => prev.filter(f => f.name !== name));

  return (
    <div>
      <div {...getRootProps()} style={s.zone(isDragActive)}>
        <input {...getInputProps()} />
        <div style={s.icon}>{isDragActive ? '📂' : '📄'}</div>
        <div style={s.title}>
          {isDragActive ? 'Drop resumes here...' : 'Drag & drop resumes here'}
        </div>
        <div style={s.sub}>or click to browse · PDF and DOCX supported</div>
      </div>

      {files.length > 0 && (
        <div style={s.fileList}>
          {files.map(f => (
            <div key={f.name} style={s.fileItem}>
              <span>{f.name.endsWith('.pdf') ? '📕' : '📘'}</span>
              <span style={{ flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{f.name}</span>
              <span style={{ color: '#9ca3af', fontSize: 11 }}>{(f.size / 1024).toFixed(0)} KB</span>
              <button style={s.removeBtn} onClick={() => remove(f.name)}>×</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
